    private List<Customer> _customers = new();
    private List<Product> _products = new();
    private List<Invoice> _invoices = new();
    private InvoiceDraft _draft = new();
    private Invoice? _selectedInvoice;
    private decimal _taxStampAmount = 1.000m;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
        ResetDraft();
    }

    private async Task LoadAsync()
    {
        _customers = await CustomerService.GetAllAsync();
        _products = await ProductService.GetAllAsync();
        _taxStampAmount = await SettingsService.GetTaxStampAmountAsync();
        _invoices = await InvoiceService.GetAllAsync();
    }

    private void ResetDraft()
    {
        _draft = new InvoiceDraft
        {
            IssueDate = DateTime.Today
        };

        AddLine();
    }

    private void AddLine()
    {
        var line = new InvoiceLineDraft();
        if (_products.Count > 0)
        {
            ApplyProductSnapshot(line, _products[0].Id);
        }

        _draft.Lines.Add(line);
    }

    private void RemoveLine(InvoiceLineDraft line)
    {
        _draft.Lines.Remove(line);
        if (_draft.Lines.Count == 0)
        {
            AddLine();
        }
    }

    private void OnProductChanged(InvoiceLineDraft line, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var productId))
        {
            ApplyProductSnapshot(line, productId);
        }
    }

    private void ApplyProductSnapshot(InvoiceLineDraft line, int productId)
    {
        line.ProductId = productId;
        var product = _products.FirstOrDefault(x => x.Id == productId);
        if (product is null)
        {
            line.ProductName = string.Empty;
            line.UnitPricePreTax = 0m;
            line.VatRate = 0m;
            return;
        }

        line.ProductName = product.Name;
        line.UnitPricePreTax = product.UnitPricePreTax;
        line.VatRate = product.VatRate;
    }

    private async Task SaveAsync()
    {
        try
        {
            if (_draft.CustomerId == 0)
            {
                _message = "Please select a customer before saving.";
                return;
            }

            var invoice = await InvoiceService.CreateAsync(_draft);
            _message = $"Invoice {invoice.InvoiceNumber} saved successfully.";
            await LoadAsync();
            ResetDraft();
            _selectedInvoice = await InvoiceService.GetByIdAsync(invoice.Id);
        }
        catch (Exception ex)
        {
            _message = ex.Message;
        }
    }

    private async Task SelectInvoice(int invoiceId)
    {
        _selectedInvoice = await InvoiceService.GetByIdAsync(invoiceId);
    }

    private decimal DraftPreTax => _draft.Lines.Sum(x => x.LinePreTax);

    private decimal DraftVat => _draft.Lines.Sum(x => x.LineVat);

    private decimal DraftPostTax => DraftPreTax + DraftVat + _taxStampAmount;

    private IReadOnlyDictionary<decimal, decimal> DraftVatByRate => _draft.Lines
        .GroupBy(x => x.VatRate)
        .ToDictionary(g => g.Key, g => g.Sum(x => x.LineVat));

    private IReadOnlyDictionary<decimal, decimal> SelectedInvoiceVatByRate => _selectedInvoice?.Lines
        .GroupBy(x => x.VatRate)
        .ToDictionary(g => g.Key, g => g.Sum(x => x.VatAmount))
        ?? new Dictionary<decimal, decimal>();

    private static string Rate(decimal value) => $"{decimal.Round(value * 100m, 0)}%";

